@patch
def fts_search(self:Table,
               q:str, # query string
               columns:list|None=None, # columns to return
               order_by:str|None=None, # order by clause
               limit:int|None=None, # limit on number of results
               offset:int|None=None, # offset for results
               where:str|None=None, # additional where clause
               where_args:dict|None=None, # args for where clause
               quote:bool=False, # quote FTS query to disable special chars
               include_rank:bool=True # include rank column
               ) -> list:
    'FTS search on any table with FTS5 enabled.'
    fts_q = self.db.quote_fts(q) if quote else q
    sql = self.search_sql(columns,order_by,limit,offset,where,include_rank)
    return self.db.q(sql, merge(dict(query=fts_q), where_args or {}))

@patch
def vec_search(self: Table,
               emb: bytes,                    # query embedding vector (as bytes)
               columns: list = None,          # columns to return (None = all)
               where: str = None,             # additional WHERE clause
               where_args: dict = None,       # args for WHERE clause
               emb_col: str = 'embedding',    # name of the embedding column
               emb_metric: str = 'cosine',    # distance metric
               dtype=np.float16,              # embedding dtype
               limit: int | None = 50,        # max results
               offset: int | None = None,     # offset for pagination
               ) -> list:
    "Vector similarity search on any table with an embedding column."
    dist = f'distance_{emb_metric}_{_dtype_suffix(dtype)}({emb_col}, :qvec)'
    sel_cols = [f'{c} as {c}' if c == 'rowid' else c for c in columns] if columns else ['*']
    sel = ','.join(sel_cols) + f', {dist} as _dist'
    wh = f'{emb_col} is not null' + (f' AND {where}' if where else '')
    return self.db.q(f'SELECT {sel} FROM {self.name} WHERE {wh} ORDER BY _dist LIMIT :limit OFFSET :offset',
                dict(qvec=emb, limit=limit, offset=ifnone(offset, 0), **(where_args or {})))

