@patch
def ann_search(self:Table,          # store table (must be ANN-registered)
               emb:bytes,           # query embedding
               columns:list=None,   # columns to return (rowid always included)
               limit:int=50,        # max results
               dtype=np.float16
               ):   # embedding dtype
    'HNSW ANN search via the store\'s usearch Index. Returns rows (+`_dist`) ordered by similarity.'
    m = self.db._ann_meta(self.name)
    if not (m and m['ndim']): return []
    idx = self.db.get_index(self.name)
    if not idx.size: return []
    res = idx.search(np.frombuffer(emb, dtype=dtype), count=limit)
    keys = np.atleast_1d(res.keys).tolist()   # -> python ints (L() would wrap the whole ndarray)
    if not keys: return []
    dist  = dict(zip(keys, np.atleast_1d(res.distances).tolist()))
    order = {k:i for i,k in enumerate(keys)}
    cols = [c for c in (columns or []) if c != 'rowid']
    sel = ','.join(cols + ['rowid']) if cols else '*, rowid'
    rows = self.db.q(f'select {sel} from {self.name} where {_in("rowid", keys)}')
    for r in rows: r['_dist'] = dist.get(r['rowid'])
    return sorted(rows, key=lambda r: order[r['rowid']])

@patch
def _idx_remove(self:Table, idx, keys):
    'Remove the keys that the index actually contains (usearch remove is not a no-op on absent keys).'
    if (present := [k for k in keys if idx.contains(k)]): idx.remove(np.array(present, dtype=np.int64))

@patch
def _sync_index(self:Table, add_ids, rm_rowids, dtype=np.float16):
    'Apply adds (by id) / removes (by rowid) to the ANN index from current blobs; infer+persist ndim; save.'
    m = self.db._ann_meta(self.name)
    if rm_rowids and m['ndim']: self._idx_remove(self.db.get_index(self.name), rm_rowids)
    rows = L(self(select='rowid, embedding', where=_in('id', add_ids))).filter(lambda r: r['embedding']) if add_ids else L()
    if rows:
        if not m['ndim']:
            m['ndim'] = len(np.frombuffer(rows[0]['embedding'], dtype=dtype))
            self.db.t.usearch_indices.update(dict(name=self.name, ndim=m['ndim']))
        idx = self.db.get_index(self.name)
        keys = rows.itemgot('rowid')
        self._idx_remove(idx, keys)   # add is not overwrite (multi=False) -> drop existing keys first (idempotent)
        idx.add(np.array(keys, dtype=np.int64),
                np.stack([np.frombuffer(b, dtype=dtype) for b in rows.itemgot('embedding')]))
    self.db._save_index(self.name)

@patch
def sync(self:Table,            # store table (hash-id; ANN mirrored if registered)
         content,               # iterable of chunk dicts with 'content'
         key_col:str=None,      # scope existing rows by this column's values (e.g. 'path','package'); None = whole table
         emb_fn=None,           # embedder for new/changed chunks
         embed:bool=True,       # embed before upsert
         force:bool=False):     # treat all content as new (skip diff)
    'Smart hash-diff update: delete stale rows, embed+upsert changed, mirror into the ANN index. Returns {changed,same,removed}.'
    content = L(content).filter(lambda d: d.get('content') and d['content'].strip())
    cont_hash = {_slug(d['content']): d for d in content}
    if force: ex = set()
    elif key_col:
        vals = {v for d in content if (v:=d.get(key_col)) is not None}
        ex = set(L(self(select='id', where=_in(key_col, vals))).itemgot('id')) if vals else set()
    else: ex = set(L(self(select='id')).itemgot('id'))
    stale  = ex - cont_hash.keys()
    to_add = filter_keys(cont_hash, not_(in_(ex)))
    m  = self.db._ann_meta(self.name)
    dt = _np_dtype.get(m['dtype'], np.float16) if m else np.float16
    rm_rowids = L(self(select='rowid', where=_in('id', stale))).itemgot('rowid') if (m and stale) else L()
    if stale: self.delete_where(where=_in('id', stale))
    if to_add: process_content(self, list(to_add.values()), embed=embed, emb_fn=emb_fn)
    if m: self._sync_index(list(to_add), list(rm_rowids), dt)
    return dict(changed=len(to_add), same=len(ex)-len(stale), removed=len(stale))

@patch
def rebuild_index(self:Table, dtype=None):
    'Rebuild the ANN Index from scratch using the embedding blobs in SQLite. Returns index size.'
    m = self.db._ann_meta(self.name)
    assert m, f'{self.name!r} is not an ANN store'
    dt = dtype or _np_dtype.get(m['dtype'], np.float16)
    rows = L(self(select='rowid, embedding')).filter(lambda r: r['embedding'])
    self.db.ann_indices.pop(self.name, None)
    if not rows:
        if not m['ndim']: return 0                                   # never had vectors; nothing to clear
        self.db.get_index(self.name, load=False).reset()  # empty index, ignore the stale sidecar
        self.db._save_index(self.name)                               # overwrite sidecar to reflect empty table
        return 0
    nd = len(np.frombuffer(rows[0]['embedding'], dtype=dt))
    if m['ndim'] != nd: self.db.t.usearch_indices.update(dict(name=self.name, ndim=nd))
    idx = self.db.get_index(self.name, load=False); idx.reset()
    idx.add(np.array(rows.itemgot('rowid'), dtype=np.int64),
            np.stack([np.frombuffer(b, dtype=dt) for b in rows.itemgot('embedding')]))
    self.db._save_index(self.name)
    return idx.size

